insert into public.knowledge_points (id,name,summary,core_fact,category,common_mistake,memory_tip,published,version) values
  ('poetry-shijing','诗经','中国最早的诗歌总集，内容按风、雅、颂分类。','《诗经》是中国最早的一部诗歌总集，分为风、雅、颂三部分。','诗歌源流','把《诗经》与《楚辞》的体裁、地域特色混淆。','诗经三分风雅颂。',true,1),
  ('poetry-chuci','楚辞','以屈原作品为主，具有鲜明的楚地文化特色和浪漫主义色彩。','《楚辞》以屈原作品为主，代表作有《离骚》。','诗歌源流','把《离骚》错配给《诗经》或汉赋。','楚辞屈原《离骚》。',true,1),
  ('poetry-li-bai','李白','唐代浪漫主义诗人，后人称“诗仙”。','李白被称为“诗仙”，代表作有《将进酒》《蜀道难》等。','唐诗','把李白与杜甫的称号、诗风混淆。','李白诗仙，浪漫飞扬。',true,1),
  ('poetry-du-fu','杜甫','唐代现实主义诗人，后人称“诗圣”。','杜甫被称为“诗圣”，其诗常反映社会现实。','唐诗','把诗仙、诗圣称号颠倒。','杜甫诗圣，诗史现实。',true,1),
  ('poetry-wang-wei','王维','唐代诗人，山水田园诗意境清幽，诗画相融。','王维有“诗佛”之称，作品常见山水、禅意与田园意境。','唐诗','把王维的风格与边塞诗、豪放词混淆。','王维诗佛，山水禅意。',true,1),
  ('poetry-bai-juyi','白居易','唐代诗人，语言平易晓畅，代表作有《琵琶行》《长恨歌》。','《琵琶行》《长恨歌》均为白居易作品。','唐诗','把白居易作品与李白、杜甫作品错配。','琵琶长恨白居易。',true,1),
  ('poetry-su-shi','苏轼','北宋文学家，词风开阔豪迈，代表作有《念奴娇·赤壁怀古》《水调歌头》。','苏轼是豪放词代表人物之一。','宋词','把苏轼的豪放词与李清照的婉约词混淆。','苏轼豪放，赤壁水调。',true,1),
  ('poetry-li-qingzhao','李清照','宋代女词人，词作多呈现婉约细腻的情感表达。','李清照是婉约词代表人物之一，代表作有《声声慢》。','宋词','将李清照与辛弃疾的词风相混。','清照婉约，《声声慢》。',true,1),
  ('poetry-xin-qiji','辛弃疾','南宋词人，作品多有报国豪情和慷慨悲壮的风格。','辛弃疾是豪放词代表人物之一，代表作有《破阵子·为陈同甫赋壮词以寄之》。','宋词','把辛弃疾的豪放爱国主题误记为婉约闺情。','辛弃疾豪放，壮志报国。',true,1),
  ('poetry-yuefu','乐府诗','乐府原为古代音乐官署，后演变为一种诗歌体裁名称。','“乐府”既指古代音乐官署，也指由此发展而来的诗歌体裁。','诗歌体裁','只把乐府理解为机构，忽略其诗歌体裁意义。','乐府先是官，后来也是诗。',true,1)
