insert into public.questions (id,knowledge_id,level_id,question_type,stem,options,correct_answer,explanation,difficulty,published,version) values
  ('poetry-origin-01','poetry-shijing','poetry-origin-1','single_choice','《诗经》的内容分类是？','{"questionId":"poetry-origin-01","knowledgeId":"poetry-shijing","type":"single_choice","stem":"《诗经》的内容分类是？","options":[{"id":"A","text":"风、雅、颂"},{"id":"B","text":"赋、比、兴"},{"id":"C","text":"诗、词、曲"},{"id":"D","text":"经、史、子、集"}]}'::jsonb,'"A"'::jsonb,'{"summary":"正确答案：风、雅、颂","whyCorrect":"《诗经》按内容分为风、雅、颂。","whyUserAnswerWrong":"赋、比、兴是《诗经》常用表现手法；诗词曲和经史子集属于其他分类。","commonMistake":"将内容分类与表现手法混用。","memoryTip":"诗经三分风雅颂。"}'::jsonb,2,true,1),
  ('poetry-origin-02','poetry-chuci','poetry-origin-1','single_choice','《离骚》的作者是？','{"questionId":"poetry-origin-02","knowledgeId":"poetry-chuci","type":"single_choice","stem":"《离骚》的作者是？","options":[{"id":"A","text":"屈原"},{"id":"B","text":"宋玉"},{"id":"C","text":"司马迁"},{"id":"D","text":"曹操"}]}'::jsonb,'"A"'::jsonb,'{"summary":"正确答案：屈原","whyCorrect":"《离骚》是屈原的代表作，也是《楚辞》重要作品。","whyUserAnswerWrong":"宋玉与楚辞有关，但《离骚》作者是屈原。","commonMistake":"将楚辞作家内部的作品归属混淆。","memoryTip":"楚辞屈原《离骚》。"}'::jsonb,1,true,1),
  ('poetry-origin-03','poetry-yuefu','poetry-origin-1','single_choice','关于“乐府”的表述，正确的是？','{"questionId":"poetry-origin-03","knowledgeId":"poetry-yuefu","type":"single_choice","stem":"关于“乐府”的表述，正确的是？","options":[{"id":"A","text":"仅指唐代的一种书法字体"},{"id":"B","text":"先指古代音乐官署，后也指诗歌体裁"},{"id":"C","text":"仅指宋词的曲牌名称"},{"id":"D","text":"专指《诗经》中的“雅”"}]}'::jsonb,'"B"'::jsonb,'{"summary":"正确答案：先指古代音乐官署，后也指诗歌体裁","whyCorrect":"乐府本为掌管音乐的官署名称，后由其采集、配乐诗歌发展为体裁名称。","whyUserAnswerWrong":"题干考查名称含义的历史演变，不应只记其中一个意思。","commonMistake":"只记住“乐府诗”，忽略其制度起源。","memoryTip":"乐府先是官，后来也是诗。"}'::jsonb,3,true,1),
  ('poetry-origin-04','poetry-shijing','poetry-origin-1','single_choice','下列属于《诗经》常用表现手法的是？','{"questionId":"poetry-origin-04","knowledgeId":"poetry-shijing","type":"single_choice","stem":"下列属于《诗经》常用表现手法的是？","options":[{"id":"A","text":"风、雅、颂"},{"id":"B","text":"赋、比、兴"},{"id":"C","text":"起、承、转、合"},{"id":"D","text":"比喻、排比、对偶"}]}'::jsonb,'"B"'::jsonb,'{"summary":"正确答案：赋、比、兴","whyCorrect":"赋、比、兴是《诗经》常用的表现手法。","whyUserAnswerWrong":"风、雅、颂是内容分类；起承转合是篇章结构概念。","commonMistake":"把“风雅颂”和“赋比兴”两组三字口诀混淆。","memoryTip":"内容风雅颂，手法赋比兴。"}'::jsonb,3,true,1),
  ('poetry-tang-song-01','poetry-li-bai','poetry-tang-song-1','single_choice','被后人称为“诗仙”的诗人是？','{"questionId":"poetry-tang-song-01","knowledgeId":"poetry-li-bai","type":"single_choice","stem":"被后人称为“诗仙”的诗人是？","options":[{"id":"A","text":"李白"},{"id":"B","text":"杜甫"},{"id":"C","text":"白居易"},{"id":"D","text":"王维"}]}'::jsonb,'"A"'::jsonb,'{"summary":"正确答案：李白","whyCorrect":"李白以浪漫主义诗风著称，后人称其为“诗仙”。","whyUserAnswerWrong":"杜甫被称为诗圣，王维有诗佛之称。","commonMistake":"把唐代诗人称号混成同一组。","memoryTip":"李白诗仙，浪漫飞扬。"}'::jsonb,1,true,1),
  ('poetry-tang-song-02','poetry-du-fu','poetry-tang-song-1','single_choice','被后人称为“诗圣”的诗人是？','{"questionId":"poetry-tang-song-02","knowledgeId":"poetry-du-fu","type":"single_choice","stem":"被后人称为“诗圣”的诗人是？","options":[{"id":"A","text":"李白"},{"id":"B","text":"杜甫"},{"id":"C","text":"李商隐"},{"id":"D","text":"白居易"}]}'::jsonb,'"B"'::jsonb,'{"summary":"正确答案：杜甫","whyCorrect":"杜甫被后人称为“诗圣”，其诗深切反映社会现实。","whyUserAnswerWrong":"李白是诗仙，白居易以平易晓畅的诗风著称。","commonMistake":"只记住“诗”字称号，忽略具体诗人。","memoryTip":"杜甫诗圣，诗史现实。"}'::jsonb,1,true,1),
  ('poetry-tang-song-03','poetry-wang-wei','poetry-tang-song-1','single_choice','有“诗佛”之称，诗作常呈现山水禅意的唐代诗人是？','{"questionId":"poetry-tang-song-03","knowledgeId":"poetry-wang-wei","type":"single_choice","stem":"有“诗佛”之称，诗作常呈现山水禅意的唐代诗人是？","options":[{"id":"A","text":"王维"},{"id":"B","text":"岑参"},{"id":"C","text":"杜牧"},{"id":"D","text":"孟浩然"}]}'::jsonb,'"A"'::jsonb,'{"summary":"正确答案：王维","whyCorrect":"王维有“诗佛”之称，山水田园诗常见清幽、禅意。","whyUserAnswerWrong":"其他诗人也有不同题材成就，但不对应诗佛称号。","commonMistake":"把山水田园诗人与边塞诗人、咏史诗人混淆。","memoryTip":"王维诗佛，山水禅意。"}'::jsonb,2,true,1),
  ('poetry-tang-song-04','poetry-bai-juyi','poetry-tang-song-1','single_choice','下列作品中，属于白居易的是？','{"questionId":"poetry-tang-song-04","knowledgeId":"poetry-bai-juyi","type":"single_choice","stem":"下列作品中，属于白居易的是？","options":[{"id":"A","text":"《蜀道难》"},{"id":"B","text":"《琵琶行》"},{"id":"C","text":"《念奴娇·赤壁怀古》"},{"id":"D","text":"《声声慢》"}]}'::jsonb,'"B"'::jsonb,'{"summary":"正确答案：《琵琶行》","whyCorrect":"《琵琶行》《长恨歌》均为白居易作品。","whyUserAnswerWrong":"《蜀道难》属李白，《念奴娇·赤壁怀古》属苏轼，《声声慢》属李清照。","commonMistake":"把跨朝代作品只按知名度混记。","memoryTip":"琵琶长恨白居易。"}'::jsonb,2,true,1),
  ('poetry-tang-song-05','poetry-su-shi','poetry-tang-song-1','single_choice','下列作品与苏轼对应的是？','{"questionId":"poetry-tang-song-05","knowledgeId":"poetry-su-shi","type":"single_choice","stem":"下列作品与苏轼对应的是？","options":[{"id":"A","text":"《念奴娇·赤壁怀古》"},{"id":"B","text":"《破阵子·为陈同甫赋壮词以寄之》"},{"id":"C","text":"《离骚》"},{"id":"D","text":"《长恨歌》"}]}'::jsonb,'"A"'::jsonb,'{"summary":"正确答案：《念奴娇·赤壁怀古》","whyCorrect":"《念奴娇·赤壁怀古》是苏轼的代表作，呈现开阔豪迈的词风。","whyUserAnswerWrong":"《破阵子》属辛弃疾，《离骚》属屈原，《长恨歌》属白居易。","commonMistake":"将豪放词作家之间的作品误配。","memoryTip":"苏轼豪放，赤壁水调。"}'::jsonb,2,true,1),
  ('poetry-tang-song-06','poetry-li-qingzhao','poetry-tang-song-1','single_choice','下列作品与李清照对应的是？','{"questionId":"poetry-tang-song-06","knowledgeId":"poetry-li-qingzhao","type":"single_choice","stem":"下列作品与李清照对应的是？","options":[{"id":"A","text":"《声声慢》"},{"id":"B","text":"《将进酒》"},{"id":"C","text":"《春望》"},{"id":"D","text":"《琵琶行》"}]}'::jsonb,'"A"'::jsonb,'{"summary":"正确答案：《声声慢》","whyCorrect":"《声声慢》是李清照代表词作，体现细腻婉约的情感表达。","whyUserAnswerWrong":"《将进酒》属李白，《春望》属杜甫，《琵琶行》属白居易。","commonMistake":"只记词风，不记具体作品。","memoryTip":"清照婉约，《声声慢》。"}'::jsonb,2,true,1),
  ('poetry-tang-song-07','poetry-xin-qiji','poetry-tang-song-1','single_choice','“醉里挑灯看剑，梦回吹角连营”出自哪位词人的作品？','{"questionId":"poetry-tang-song-07","knowledgeId":"poetry-xin-qiji","type":"single_choice","stem":"“醉里挑灯看剑，梦回吹角连营”出自哪位词人的作品？","options":[{"id":"A","text":"辛弃疾"},{"id":"B","text":"苏轼"},{"id":"C","text":"柳永"},{"id":"D","text":"李清照"}]}'::jsonb,'"A"'::jsonb,'{"summary":"正确答案：辛弃疾","whyCorrect":"该句出自辛弃疾《破阵子·为陈同甫赋壮词以寄之》，体现其报国豪情。","whyUserAnswerWrong":"苏轼同属豪放词代表，但此句和作品归属辛弃疾。","commonMistake":"把豪放词人的作品只按风格判断而不记作者。","memoryTip":"挑灯看剑、吹角连营，辛弃疾壮志。"}'::jsonb,3,true,1),
  ('poetry-tang-song-08','poetry-su-shi','poetry-tang-song-1','single_choice','下列对词风的判断，正确的是？','{"questionId":"poetry-tang-song-08","knowledgeId":"poetry-su-shi","type":"single_choice","stem":"下列对词风的判断，正确的是？","options":[{"id":"A","text":"苏轼是婉约词代表，作品多写闺情"},{"id":"B","text":"李清照是豪放词代表，作品多写边塞"},{"id":"C","text":"苏轼是豪放词代表之一"},{"id":"D","text":"辛弃疾以宫体诗著称"}]}'::jsonb,'"C"'::jsonb,'{"summary":"正确答案：苏轼是豪放词代表之一","whyCorrect":"苏轼词风开阔豪迈，是豪放词代表人物之一。","whyUserAnswerWrong":"李清照多为婉约词风；辛弃疾也以豪放和报国主题著称。","commonMistake":"把豪放、婉约当成作者唯一标签，忽略代表性而非绝对性。","memoryTip":"苏轼辛弃疾豪放，李清照婉约。"}'::jsonb,3,true,1),
  ('poetry-tang-song-09','poetry-du-fu','poetry-tang-song-1','single_choice','《春望》的作者是？','{"questionId":"poetry-tang-song-09","knowledgeId":"poetry-du-fu","type":"single_choice","stem":"《春望》的作者是？","options":[{"id":"A","text":"李白"},{"id":"B","text":"白居易"},{"id":"C","text":"王维"},{"id":"D","text":"杜甫"}]}'::jsonb,'"D"'::jsonb,'{"summary":"正确答案：杜甫","whyCorrect":"《春望》是杜甫代表作，反映战乱背景中的忧国忧民情感。","whyUserAnswerWrong":"李白、王维、白居易也都是唐代诗人，需结合具体作品判断。","commonMistake":"只按同为唐诗人而互换作品。","memoryTip":"春望看杜甫，现实忧思深。"}'::jsonb,2,true,1),
  ('poetry-tang-song-10','poetry-su-shi','poetry-tang-song-1','single_choice','“但愿人长久，千里共婵娟”出自谁的作品？','{"questionId":"poetry-tang-song-10","knowledgeId":"poetry-su-shi","type":"single_choice","stem":"“但愿人长久，千里共婵娟”出自谁的作品？","options":[{"id":"A","text":"辛弃疾"},{"id":"B","text":"李清照"},{"id":"C","text":"苏轼"},{"id":"D","text":"柳永"}]}'::jsonb,'"C"'::jsonb,'{"summary":"正确答案：苏轼","whyCorrect":"该句出自苏轼《水调歌头·明月几时有》。","whyUserAnswerWrong":"不要仅凭“月”这一意象把作品归给其他词人。","commonMistake":"把宋词名句只背诵不对应作者和篇名。","memoryTip":"水调明月苏轼，千里共婵娟。"}'::jsonb,2,true,1),
  ('poetry-boss-01','poetry-shijing','poetry-boss','single_choice','下列关于中国古代诗歌源流的表述，正确的是？','{"questionId":"poetry-boss-01","knowledgeId":"poetry-shijing","type":"single_choice","stem":"下列关于中国古代诗歌源流的表述，正确的是？","options":[{"id":"A","text":"《诗经》按风、雅、颂分类"},{"id":"B","text":"《离骚》是《诗经》中的作品"},{"id":"C","text":"乐府只指一种书法字体"},{"id":"D","text":"《楚辞》以唐代诗人为主"}]}'::jsonb,'"A"'::jsonb,'{"summary":"正确答案：《诗经》按风、雅、颂分类","whyCorrect":"《诗经》内容分风、雅、颂；《离骚》属《楚辞》，乐府兼具官署和体裁含义。","whyUserAnswerWrong":"源流题常将作品归属、分类与体裁名称交叉设置。","commonMistake":"将《诗经》《楚辞》及乐府混为同一体系。","memoryTip":"诗经风雅颂，楚辞屈原离骚。"}'::jsonb,3,true,1),
  ('poetry-boss-02','poetry-li-bai','poetry-boss','single_choice','下列“诗人—称号—作品”对应正确的是？','{"questionId":"poetry-boss-02","knowledgeId":"poetry-li-bai","type":"single_choice","stem":"下列“诗人—称号—作品”对应正确的是？","options":[{"id":"A","text":"李白—诗仙—《将进酒》"},{"id":"B","text":"杜甫—诗仙—《声声慢》"},{"id":"C","text":"白居易—诗佛—《蜀道难》"},{"id":"D","text":"王维—诗圣—《破阵子》"}]}'::jsonb,'"A"'::jsonb,'{"summary":"正确答案：李白—诗仙—《将进酒》","whyCorrect":"李白被称为诗仙，《将进酒》为其代表作。","whyUserAnswerWrong":"诗仙、诗圣、诗佛以及作品所属作者是常见交叉干扰点。","commonMistake":"把称号、诗人、作品拆开记，无法做组合题。","memoryTip":"诗仙李白将进酒，诗圣杜甫看现实，诗佛王维山水禅。"}'::jsonb,3,true,1),
  ('poetry-boss-03','poetry-du-fu','poetry-boss','single_choice','下列作品按作者生活时代先后排序，最合理的是？','{"questionId":"poetry-boss-03","knowledgeId":"poetry-du-fu","type":"single_choice","stem":"下列作品按作者生活时代先后排序，最合理的是？","options":[{"id":"A","text":"《声声慢》—《春望》—《离骚》"},{"id":"B","text":"《离骚》—《春望》—《声声慢》"},{"id":"C","text":"《春望》—《离骚》—《声声慢》"},{"id":"D","text":"《声声慢》—《离骚》—《春望》"}]}'::jsonb,'"B"'::jsonb,'{"summary":"正确答案：《离骚》—《春望》—《声声慢》","whyCorrect":"屈原生活在先秦，杜甫为唐代，李清照为宋代。","whyUserAnswerWrong":"先按作者定位时代，再比较作品先后，避免只按作品题材猜测。","commonMistake":"把唐诗、宋词与先秦楚辞的时序颠倒。","memoryTip":"屈原先秦，杜甫唐，清照宋。"}'::jsonb,4,true,1),
  ('poetry-boss-04','poetry-xin-qiji','poetry-boss','single_choice','下列关于宋词的表述，正确的是？','{"questionId":"poetry-boss-04","knowledgeId":"poetry-xin-qiji","type":"single_choice","stem":"下列关于宋词的表述，正确的是？","options":[{"id":"A","text":"辛弃疾作品常见报国豪情"},{"id":"B","text":"李清照是边塞诗派代表"},{"id":"C","text":"苏轼《离骚》开创楚辞"},{"id":"D","text":"白居易是南宋豪放词人"}]}'::jsonb,'"A"'::jsonb,'{"summary":"正确答案：辛弃疾作品常见报国豪情","whyCorrect":"辛弃疾是南宋豪放词代表人物，其作品多有爱国报国的慷慨主题。","whyUserAnswerWrong":"李清照为婉约词代表；《离骚》作者为屈原；白居易是唐代诗人。","commonMistake":"把不同朝代、体裁与作者的标签叠加到同一人身上。","memoryTip":"辛弃疾豪放，壮志报国。"}'::jsonb,3,true,1),
  ('poetry-boss-05','poetry-bai-juyi','poetry-boss','single_choice','下列作品与作者对应错误的是？','{"questionId":"poetry-boss-05","knowledgeId":"poetry-bai-juyi","type":"single_choice","stem":"下列作品与作者对应错误的是？","options":[{"id":"A","text":"《琵琶行》—白居易"},{"id":"B","text":"《念奴娇·赤壁怀古》—苏轼"},{"id":"C","text":"《声声慢》—李清照"},{"id":"D","text":"《蜀道难》—杜甫"}]}'::jsonb,'"D"'::jsonb,'{"summary":"正确答案：《蜀道难》—杜甫","whyCorrect":"《蜀道难》作者是李白，不是杜甫。","whyUserAnswerWrong":"其余三项均为正确的作者作品对应。","commonMistake":"李白、杜甫均为唐诗大家，最易发生作品错配。","memoryTip":"蜀道难看李白，春望看杜甫。"}'::jsonb,3,true,1),
  ('poetry-boss-06','poetry-wang-wei','poetry-boss','single_choice','下列对诗歌风格的概括，最准确的是？','{"questionId":"poetry-boss-06","knowledgeId":"poetry-wang-wei","type":"single_choice","stem":"下列对诗歌风格的概括，最准确的是？","options":[{"id":"A","text":"王维诗作常见山水田园与禅意"},{"id":"B","text":"杜甫诗作以婉约闺情为主"},{"id":"C","text":"李白以现实主义沉郁顿挫著称"},{"id":"D","text":"辛弃疾以宫体艳情词著称"}]}'::jsonb,'"A"'::jsonb,'{"summary":"正确答案：王维诗作常见山水田园与禅意","whyCorrect":"王维有诗佛之称，诗作常营造山水田园和清幽禅意。","whyUserAnswerWrong":"杜甫以现实关怀著称，李白具有浪漫主义诗风，辛弃疾多报国豪情。","commonMistake":"用一个流派标签替换诗人的具体风格。","memoryTip":"王维诗佛，山水禅意。"}'::jsonb,3,true,1)
